# a + b > g

#!/usr/bin/env python3
from sage.all import *
from sage.groups.generic import bsgs


g=3040871967959800581351382295274005388082419270793259228509099272494086612979335548205806725469849481228948811909984262857772287453967175931780503026101
nbits = 2048
gamma = 0.23
# gamma = 500/(1024*2) #记得调gamma参数和nbits
cbits = ceil(nbits * (0.5 - 2 * gamma))

M = (N - 1) // (2 * g)
u = M // (2 * g)
v = M - 2 * g * u
GF = Zmod(N)
x = GF.random_element()
y = x ** (2 * g)
# c的范围大概与N^(0.5-2*gamma)很接近
lower = ZZ(2**(cbits-1))
upper = ZZ(2**(cbits+1))
c = bsgs(y, y ** u, (lower, upper))
ab = u - c
apb = v + 2 * g * c
P = PolynomialRing(ZZ, 'x')
x = P.gen()
f = x ** 2 - apb * x + ab
a = f.roots()
if a:
    a, b = a[0][0], a[1][0]
    p = 2 * g * a + 1
    q = 2 * g * b + 1
    assert p * q == N

    print(f'p =',p)
    print(f'q =',q)
